47: // Webhook is an abstract admission plugin with all the infrastructure to define Admit or Validate on-top.
48: type Webhook struct {
49: 	*admission.Handler
50: 
51: 	sourceFactory sourceFactory
52: 
53: 	hookSource       Source
54: 	clientManager    *webhookutil.ClientManager
55: 	namespaceMatcher *namespace.Matcher
56: 	objectMatcher    *object.Matcher
57: 	dispatcher       Dispatcher
58: 	filterCompiler   cel.ConditionCompiler
59: 	authorizer       authorizer.Authorizer
60: }
61: 
62: var (
63: 	_ genericadmissioninit.WantsExternalKubeClientSet = &Webhook{}
64: 	_ admission.Interface                             = &Webhook{}
65: )
