67: type sourceFactory func(f informers.SharedInformerFactory) Source
68: type dispatcherFactory func(cm *webhookutil.ClientManager) Dispatcher
69: 
70: // NewWebhook creates a new generic admission webhook.
71: func NewWebhook(handler *admission.Handler, configFile io.Reader, sourceFactory sourceFactory, dispatcherFactory dispatcherFactory) (*Webhook, error) {
72: 	kubeconfigFile, err := config.LoadConfig(configFile)
73: 	if err != nil {
74: 		return nil, err
75: 	}
76: 
77: 	cm, err := webhookutil.NewClientManager(
78: 		[]schema.GroupVersion{
79: 			admissionv1beta1.SchemeGroupVersion,
80: 			admissionv1.SchemeGroupVersion,
81: 		},
82: 		admissionv1beta1.AddToScheme,
83: 		admissionv1.AddToScheme,
84: 	)
85: 	if err != nil {
86: 		return nil, err
87: 	}
88: 	authInfoResolver, err := webhookutil.NewDefaultAuthenticationInfoResolver(kubeconfigFile)
89: 	if err != nil {
90: 		return nil, err
91: 	}
92: 	// Set defaults which may be overridden later.
93: 	cm.SetAuthenticationInfoResolver(authInfoResolver)
94: 	cm.SetServiceResolver(webhookutil.NewDefaultServiceResolver())
95: 
96: 	return &Webhook{
97: 		Handler:          handler,
98: 		sourceFactory:    sourceFactory,
99: 		clientManager:    &cm,
100: 		namespaceMatcher: &namespace.Matcher{},
101: 		objectMatcher:    &object.Matcher{},
102: 		dispatcher:       dispatcherFactory(&cm),
103: 		filterCompiler:   cel.NewConditionCompiler(environment.MustBaseEnvSet(environment.DefaultCompatibilityVersion())),
104: 	}, nil
105: }
