126: // SetExternalKubeInformerFactory implements the WantsExternalKubeInformerFactory interface.
127: func (a *Webhook) SetExternalKubeInformerFactory(f informers.SharedInformerFactory) {
128: 	namespaceInformer := f.Core().V1().Namespaces()
129: 	a.namespaceMatcher.NamespaceLister = namespaceInformer.Lister()
130: 	a.hookSource = a.sourceFactory(f)
131: 	a.SetReadyFunc(func() bool {
132: 		return namespaceInformer.Informer().HasSynced() && a.hookSource.HasSynced()
