140: // ValidateInitialization implements the InitializationValidator interface.
141: func (a *Webhook) ValidateInitialization() error {
142: 	if a.hookSource == nil {
143: 		return fmt.Errorf("kubernetes client is not properly setup")
144: 	}
145: 	if err := a.namespaceMatcher.Validate(); err != nil {
146: 		return fmt.Errorf("namespaceMatcher is not properly setup: %v", err)
147: 	}
148: 	if err := a.clientManager.Validate(); err != nil {
149: 		return fmt.Errorf("clientManager is not properly setup: %v", err)
150: 	}
151: 	return nil
152: }
