154: // ShouldCallHook returns invocation details if the webhook should be called, nil if the webhook should not be called,
155: // or an error if an error was encountered during evaluation.
156: func (a *Webhook) ShouldCallHook(ctx context.Context, h webhook.WebhookAccessor, attr admission.Attributes, o admission.ObjectInterfaces, v VersionedAttributeAccessor) (*WebhookInvocation, *apierrors.StatusError) {
157: 	matches, matchNsErr := a.namespaceMatcher.MatchNamespaceSelector(h, attr)
158: 	// Should not return an error here for webhooks which do not apply to the request, even if err is an unexpected scenario.
159: 	if !matches && matchNsErr == nil {
160: 		return nil, nil
161: 	}
162: 
163: 	// Should not return an error here for webhooks which do not apply to the request, even if err is an unexpected scenario.
164: 	matches, matchObjErr := a.objectMatcher.MatchObjectSelector(h, attr)
165: 	if !matches && matchObjErr == nil {
166: 		return nil, nil
167: 	}
168: 
169: 	var invocation *WebhookInvocation
170: 	for _, r := range h.GetRules() {
171: 		m := rules.Matcher{Rule: r, Attr: attr}
172: 		if m.Matches() {
173: 			invocation = &WebhookInvocation{
174: 				Webhook:     h,
175: 				Resource:    attr.GetResource(),
176: 				Subresource: attr.GetSubresource(),
177: 				Kind:        attr.GetKind(),
178: 			}
179: 			break
180: 		}
181: 	}
182: 	if invocation == nil && h.GetMatchPolicy() != nil && *h.GetMatchPolicy() == v1.Equivalent {
183: 		attrWithOverride := &attrWithResourceOverride{Attributes: attr}
184: 		equivalents := o.GetEquivalentResourceMapper().EquivalentResourcesFor(attr.GetResource(), attr.GetSubresource())
185: 		// honor earlier rules first
186: 	OuterLoop:
187: 		for _, r := range h.GetRules() {
188: 			// see if the rule matches any of the equivalent resources
189: 			for _, equivalent := range equivalents {
190: 				if equivalent == attr.GetResource() {
191: 					// exclude attr.GetResource(), which we already checked
192: 					continue
193: 				}
194: 				attrWithOverride.resource = equivalent
195: 				m := rules.Matcher{Rule: r, Attr: attrWithOverride}
196: 				if m.Matches() {
197: 					kind := o.GetEquivalentResourceMapper().KindFor(equivalent, attr.GetSubresource())
198: 					if kind.Empty() {
199: 						return nil, apierrors.NewInternalError(fmt.Errorf("unable to convert to %v: unknown kind", equivalent))
200: 					}
201: 					invocation = &WebhookInvocation{
202: 						Webhook:     h,
203: 						Resource:    equivalent,
204: 						Subresource: attr.GetSubresource(),
205: 						Kind:        kind,
206: 					}
207: 					break OuterLoop
208: 				}
209: 			}
210: 		}
211: 	}
212: 
213: 	if invocation == nil {
214: 		return nil, nil
215: 	}
216: 	if matchNsErr != nil {
217: 		return nil, matchNsErr
218: 	}
219: 	if matchObjErr != nil {
220: 		return nil, matchObjErr
221: 	}
222: 	matchConditions := h.GetMatchConditions()
223: 	if len(matchConditions) > 0 {
224: 		versionedAttr, err := v.VersionedAttribute(invocation.Kind)
225: 		if err != nil {
226: 			return nil, apierrors.NewInternalError(err)
227: 		}
228: 
229: 		matcher := h.GetCompiledMatcher(a.filterCompiler)
230: 		matchResult := matcher.Match(ctx, versionedAttr, nil, a.authorizer)
231: 
232: 		if matchResult.Error != nil {
233: 			klog.Warningf("Failed evaluating match conditions, failing closed %v: %v", h.GetName(), matchResult.Error)
234: 			return nil, apierrors.NewForbidden(attr.GetResource().GroupResource(), attr.GetName(), matchResult.Error)
235: 		} else if !matchResult.Matches {
236: 			admissionmetrics.Metrics.ObserveMatchConditionExclusion(ctx, h.GetName(), "webhook", h.GetType(), string(attr.GetOperation()))
237: 			// if no match, always skip webhook
238: 			return nil, nil
239: 		}
240: 	}
241: 
242: 	return invocation, nil
243: }
244: 
245: type attrWithResourceOverride struct {
246: 	admission.Attributes
247: 	resource schema.GroupVersionResource
248: }
249: 
250: func (a *attrWithResourceOverride) GetResource() schema.GroupVersionResource { return a.resource }
251: 
252: // Dispatch is called by the downstream Validate or Admit methods.
253: func (a *Webhook) Dispatch(ctx context.Context, attr admission.Attributes, o admission.ObjectInterfaces) error {
254: 	if rules.IsExemptAdmissionConfigurationResource(attr) {
255: 		return nil
256: 	}
257: 	if !a.WaitForReady() {
258: 		return admission.NewForbidden(attr, fmt.Errorf("not yet ready to handle request"))
259: 	}
260: 	hooks := a.hookSource.Webhooks()
261: 	return a.dispatcher.Dispatch(ctx, attr, o, hooks)
262: }
