34: // WebhookAccessor provides a common interface to both mutating and validating webhook types.
35: type WebhookAccessor interface {
36: 	// This accessor provides the methods needed to support matching against webhook
37: 	// predicates
38: 	namespace.NamespaceSelectorProvider
39: 	object.ObjectSelectorProvider
40: 
