45: 	GetConfigurationName() string
46: 
47: 	// GetRESTClient gets the webhook client
48: 	GetRESTClient(clientManager *webhookutil.ClientManager) (*rest.RESTClient, error)
49: 
50: 	// GetCompiledMatcher gets the compiled matcher object
51: 	GetCompiledMatcher(compiler cel.ConditionCompiler) matchconditions.Matcher
52: 
53: 	// GetName gets the webhook Name field. Note that the name is scoped to the webhook
54: 	// configuration and does not provide a globally unique identity, if a unique identity is
