62: 	GetFailurePolicy() *v1.FailurePolicyType
63: 	// GetMatchPolicy gets the webhook MatchPolicy field.
64: 	GetMatchPolicy() *v1.MatchPolicyType
65: 	// GetNamespaceSelector gets the webhook NamespaceSelector field.
66: 	GetNamespaceSelector() *metav1.LabelSelector
67: 	// GetObjectSelector gets the webhook ObjectSelector field.
68: 	GetObjectSelector() *metav1.LabelSelector
69: 	// GetSideEffects gets the webhook SideEffects field.
70: 	GetSideEffects() *v1.SideEffectClass
71: 	// GetTimeoutSeconds gets the webhook TimeoutSeconds field.
72: 	GetTimeoutSeconds() *int32
73: 	// GetAdmissionReviewVersions gets the webhook AdmissionReviewVersions field.
74: 	GetAdmissionReviewVersions() []string
75: 
76: 	// GetMatchConditions gets the webhook match conditions field.
77: 	GetMatchConditions() []v1.MatchCondition
78: 
79: 	// GetMutatingWebhook if the accessor contains a MutatingWebhook, returns it and true, else returns false.
80: 	GetMutatingWebhook() (*v1.MutatingWebhook, bool)
81: 	// GetValidatingWebhook if the accessor contains a ValidatingWebhook, returns it and true, else returns false.
82: 	GetValidatingWebhook() (*v1.ValidatingWebhook, bool)
