352: // hookClientConfigForWebhook construct a webhookutil.ClientConfig using a WebhookAccessor to access
353: // v1beta1.MutatingWebhook and v1beta1.ValidatingWebhook API objects.  webhookutil.ClientConfig is used
354: // to create a HookClient and the purpose of the config struct is to share that with other packages
355: // that need to create a HookClient.
356: func hookClientConfigForWebhook(w WebhookAccessor) webhookutil.ClientConfig {
357: 	ret := webhookutil.ClientConfig{Name: w.GetName(), CABundle: w.GetClientConfig().CABundle}
358: 	if w.GetClientConfig().URL != nil {
359: 		ret.URL = *w.GetClientConfig().URL
360: 	}
361: 	if w.GetClientConfig().Service != nil {
362: 		ret.Service = &webhookutil.ClientConfigService{
363: 			Name:      w.GetClientConfig().Service.Name,
364: 			Namespace: w.GetClientConfig().Service.Namespace,
365: 		}
366: 		if w.GetClientConfig().Service.Port != nil {
367: 			ret.Service.Port = *w.GetClientConfig().Service.Port
368: 		} else {
369: 			ret.Service.Port = 443
370: 		}
371: 		if w.GetClientConfig().Service.Path != nil {
372: 			ret.Service.Path = *w.GetClientConfig().Service.Path
373: 		}
374: 	}
375: 	return ret
376: }
